//! JS-callable + NAPI surface for the Whisper speech-to-text pipeline (Pneuma).
//!
//! Reference: arXiv 2212.04356 (Whisper — Robust Speech Recognition via
//! Large-Scale Weak Supervision, Radford et al. 2022).
//! https://arxiv.org/abs/2212.04356
//!
//! Mirrors `crate::wasm_bindings::WasmLlamaPipeline` (the LLM JS surface).
//! Two parallel wrappers live here:
//!
//!   wasm32        →  `WasmWhisperPipeline`   (`#[wasm_bindgen]`, JS-callable)
//!   napi feature  →  `WhisperPipeline`       (`#[napi]`, Node.js-callable)
//!
//! Both wrappers carry the same shape — encoder + decoder + cached config —
//! and expose three methods:
//!
//!   `new(backend, config_json)`
//!   `encode(mel) -> Vec<f32>`        // run encoder over an 80×3000 mel
//!   `generate(encoder_output, max_tokens, eos_token) -> Vec<u32>`
//!
//! `generate` runs greedy decoding (argmax sampling) starting from a BOS
//! token (`50258` for whisper-tiny.en) and stops at `eos_token` or
//! `max_tokens`, whichever comes first. Sampling temperature, beam search,
//! and language tokens are out of scope for v1; if the host wants those it
//! can drive the decoder one step at a time and pick its own next token.
//!
//! Cross-file deps:
//!   - `crate::model_whisper_encoder::WhisperEncoder`           (Agent B)
//!   - `crate::model_whisper_decoder::WhisperDecoder`           (Agent C)
//!   - `crate::loader_whisper::{WhisperConfig, parse_whisper_config}` (Agent D)
//!
//! All three are wired in via direct `use crate::...` imports; this
//! file carries no agent stubs at the time of landing.

#![allow(dead_code)]

use std::sync::Arc;

// ─────────────────────────────────────────────────────────────────────────
// Cross-agent imports
// ─────────────────────────────────────────────────────────────────────────

use crate::loader::WeightBackend;
use crate::loader_whisper::{parse_whisper_config, WhisperConfig};
use crate::model_whisper_decoder::WhisperDecoder;
use crate::model_whisper_encoder::WhisperEncoder;

// ─────────────────────────────────────────────────────────────────────────
// Shared core (target-agnostic)
// ─────────────────────────────────────────────────────────────────────────

/// BOS token id used by the multilingual whisper checkpoints (`50258`).
/// English-only checkpoints use `50257` instead. Callers that pass an
/// explicit `eos_token` in `generate` typically also pre-seed with the
/// right BOS via the `bos_token` constructor parameter.
const DEFAULT_WHISPER_BOS: u32 = 50258;

/// Default forced decoder prefix for multilingual whisper transcription in
/// English with no timestamps. This is the load-bearing fix for the
/// "decodes Malay garbage" bug: seeding the decoder with BOS alone lets
/// greedy argmax pick a wrong `<|lang|>` token on step 1, and every
/// subsequent token compounds that error. OpenAI Whisper and HF both
/// **force** this prefix instead of predicting it:
///
///   `50258` `<|startoftranscript|>`  (SOT)
///   `50259` `<|en|>`                 (language = English)
///   `50359` `<|transcribe|>`         (task = transcribe, not translate)
///   `50363` `<|notimestamps|>`       (suppress timestamp tokens)
///
/// Mirrors the proven prefix in the `voice-stt` WASM crate's `whisper.rs`.
const DEFAULT_FORCED_PREFIX: &[u32] = &[50258, 50259, 50359, 50363];

/// End-of-transcript token (`<|endoftext|>`) for multilingual whisper.
/// `generate` stops when greedy argmax emits this. Callers can still pass
/// a different `eos_token` to `generate`; the prefix-aware loop honours
/// whichever the caller supplies (default callers pass `50257`).
const DEFAULT_WHISPER_EOT: u32 = 50257;

/// Inner pipeline shared by both the WASM and NAPI wrappers. Holds the
/// encoder + decoder + a copy of the resolved `WhisperConfig`. The
/// wrappers are thin newtypes so the WASM ABI (no generics, no `&dyn
/// Trait` across the boundary) and NAPI (heap-allocated, owned-by-Node)
/// constraints stay isolated from the engine logic.
pub struct WhisperPipelineInner {
    encoder: WhisperEncoder,
    decoder: WhisperDecoder,
    config: WhisperConfig,
    /// BOS token to seed the decoder. Defaults to `DEFAULT_WHISPER_BOS`
    /// (multilingual checkpoint). Construct-time configurable so the
    /// host can pick the right special token for English-only or
    /// translation-prefixed prompts.
    bos_token: u32,
    /// Forced decoder prefix run through `decode_step` (advancing
    /// position + KV) BEFORE greedy decoding begins. The decoder's
    /// predictions during the prefix are discarded — we feed the next
    /// forced token regardless. Defaults to `DEFAULT_FORCED_PREFIX`
    /// (`<|sot|><|en|><|transcribe|><|notimestamps|>`). Set to an empty
    /// vector to restore the legacy BOS-only behaviour, or to a custom
    /// prompt for other languages / translation / timestamped decoding.
    forced_prefix: Vec<u32>,
}

impl WhisperPipelineInner {
    /// Build a pipeline from a backend + the parsed `WhisperConfig`.
    /// The encoder and decoder share the same `Arc<dyn WeightBackend>`
    /// — they read disjoint tensor names so there's no contention on
    /// the underlying cache.
    pub fn new(backend: Arc<dyn WeightBackend>, config: WhisperConfig) -> Self {
        let encoder = WhisperEncoder::new(config.clone(), Arc::clone(&backend));
        let decoder = WhisperDecoder::new(config.clone(), backend);
        Self {
            encoder,
            decoder,
            config,
            bos_token: DEFAULT_WHISPER_BOS,
            forced_prefix: DEFAULT_FORCED_PREFIX.to_vec(),
        }
    }

    /// Run the encoder over a mel-spectrogram input. `mel` is row-major
    /// `(n_mels=80, n_frames=3000)`; the returned vector is row-major
    /// `(n_audio_ctx=1500, encoder_hidden_dim)`. The host typically
    /// caches the returned vector and re-uses it across many `generate`
    /// calls (e.g. beam variants or forced-prompt experiments).
    pub fn encode(&mut self, mel: &[f32]) -> Vec<f32> {
        self.encoder.forward(mel)
    }

    /// Greedy decoding loop with a **forced prefix**.
    ///
    ///   1. reset self-attn KV cache
    ///   2. prepare cross-attn from `encoder_output`
    ///   3. feed the forced prefix through `decode_step` one token at a
    ///      time, advancing `pos` and the self-attn KV cache; the
    ///      decoder's predictions during the prefix are discarded. The
    ///      forced prefix sets the language / task / timestamp policy so
    ///      greedy decoding can't lock onto the wrong `<|lang|>` token on
    ///      step 1 (the "Malay garbage" bug).
    ///   4. continue greedily for up to `max_tokens` NEW tokens:
    ///        - logits = decode_step(prev_token, pos)
    ///        - next  = argmax(logits)
    ///        - if next == eos_token: stop
    ///        - emit next; prev_token = next; pos += 1
    ///
    /// Returns the generated token ids (forced prefix NOT included; EOT
    /// NOT included). On `max_tokens == 0` returns an empty vector. The
    /// decoder's KV cache is reset on entry so back-to-back `generate`
    /// calls on the same pipeline are independent.
    ///
    /// If `forced_prefix` is empty the loop falls back to the legacy
    /// behaviour: seed with `bos_token`, greedy-decode from position 0.
    pub fn generate(
        &mut self,
        encoder_output: &[f32],
        max_tokens: u32,
        eos_token: u32,
    ) -> Vec<u32> {
        self.decoder.reset();
        self.decoder.prepare_audio_context(encoder_output);

        let cap = max_tokens as usize;
        let mut out: Vec<u32> = Vec::with_capacity(cap);
        if cap == 0 {
            return out;
        }

        let n_text_ctx = self.config.n_text_ctx;
        let mut pos = 0usize;

        // ── Forced prefix: feed each prefix token, discard its prediction ──
        // The decoder consumes the token at `pos` and returns the
        // distribution for `pos + 1`; we ignore that and feed the next
        // forced token. After the prefix, `pos` points at the first
        // free-generation position.
        let prefix: &[u32] = if self.forced_prefix.is_empty() {
            // Legacy fallback: a one-token "prefix" of just BOS.
            std::slice::from_ref(&self.bos_token)
        } else {
            &self.forced_prefix
        };

        // We need the next token to feed AFTER the prefix. Run the prefix
        // and capture the argmax produced by the LAST prefix token — that
        // is the first real prediction.
        let mut next_after_prefix: u32 = eos_token;
        for (i, &tok) in prefix.iter().enumerate() {
            if pos >= n_text_ctx {
                return out;
            }
            let logits = self.decoder.decode_step(tok, pos);
            pos += 1;
            if i + 1 == prefix.len() {
                next_after_prefix = argmax_u32(&logits);
            }
        }

        // ── Greedy free generation up to `max_tokens` new tokens ──────────
        let mut prev = next_after_prefix;
        for _ in 0..cap {
            if prev == eos_token {
                break;
            }
            if pos >= n_text_ctx {
                break;
            }
            out.push(prev);
            let logits = self.decoder.decode_step(prev, pos);
            pos += 1;
            prev = argmax_u32(&logits);
        }
        out
    }

    /// Override the forced decoder prefix used by the next `generate`
    /// call. Pass an empty vector to restore the legacy BOS-only seeding.
    /// See [`DEFAULT_FORCED_PREFIX`] for the multilingual-English default.
    pub fn set_forced_prefix(&mut self, prefix: Vec<u32>) {
        self.forced_prefix = prefix;
    }

    fn load_audio_context(&mut self, encoder_output: &[f32]) {
        self.decoder.reset();
        self.decoder.prepare_audio_context(encoder_output);
    }

    fn reset_decoder(&mut self) {
        self.decoder.reset();
    }

    fn decode_step_logits(&mut self, token: u32, pos: u32) -> Vec<f32> {
        self.decoder.decode_step(token, pos as usize)
    }

    fn memo_enable(&mut self, on: bool) {
        self.decoder.memo_enable(on);
    }

    fn memo_stats(&self) -> Vec<u32> {
        let (hits, misses, evictions) = self.decoder.memo_stats();
        vec![hits as u32, misses as u32, evictions as u32]
    }

    fn memo_clear(&mut self) {
        self.decoder.memo_clear();
    }
}

/// Greedy `argmax` over a logits slice. Returns the index of the
/// largest value as a `u32` (vocab_size ≤ 65k for all whisper variants
/// — fits comfortably in `u32`). Empty input returns `0`; the
/// generation loop guards that path by checking `max_tokens` before
/// the first call.
#[inline]
fn argmax_u32(logits: &[f32]) -> u32 {
    let mut best_idx: u32 = 0;
    let mut best_val: f32 = f32::NEG_INFINITY;
    for (i, &v) in logits.iter().enumerate() {
        if v > best_val {
            best_val = v;
            best_idx = i as u32;
        }
    }
    best_idx
}

/// Parse the JSON-stringified whisper config. Accepts either the
/// canonical `{ "config": {...} }` envelope or the bare config object;
/// if the top-level has a `config` key we descend into it before
/// handing the value to `parse_whisper_config`. Mirrors the same
/// envelope-tolerance pattern used by `WasmHostBackend::new` for
/// tensor-map JSON.
fn parse_whisper_config_json(config_json: &str) -> Result<WhisperConfig, String> {
    let value: serde_json::Value =
        serde_json::from_str(config_json).map_err(|e| format!("config_json parse: {}", e))?;
    let inner = value.get("config").unwrap_or(&value);
    parse_whisper_config(inner)
}

// ─────────────────────────────────────────────────────────────────────────
// WASM wrapper (wasm32 only)
// ─────────────────────────────────────────────────────────────────────────

#[cfg(target_arch = "wasm32")]
mod wasm_surface {
    use super::*;
    use crate::wasm_bindings::WasmHostBackend;
    use wasm_bindgen::prelude::*;

    /// JS-callable Whisper STT pipeline.
    ///
    /// Construction is two-step: the JS host first builds a
    /// `WasmHostBackend` (same backend used for the LLM path) and
    /// pre-populates the whisper tensor names, then constructs this
    /// wrapper. Encoding and decoding share the backend handle —
    /// nothing special-cased on the JS side.
    #[wasm_bindgen]
    pub struct WasmWhisperPipeline {
        inner: WhisperPipelineInner,
    }

    #[wasm_bindgen]
    impl WasmWhisperPipeline {
        /// Construct from a `WasmHostBackend` and a JSON config string.
        ///
        /// `backend` is taken by reference (not by value) so the JS
        /// handle stays alive for `set_tensor` / `evict` calls that
        /// run between the encoder pass and the decode loop. Same
        /// rationale as `WasmLlamaPipeline::from_backend` — taking
        /// the wrapper by value triggers a `__rt::throw_null` panic
        /// on the next `set_tensor` because wasm-bindgen zeros
        /// `__wbg_ptr` on consumed wrappers.
        ///
        /// `config_json` is the stringified `WhisperConfig` (see Agent
        /// D). Either `{ "config": {...} }` or the bare config object
        /// is accepted.
        #[wasm_bindgen(constructor)]
        pub fn new(
            backend: &WasmHostBackend,
            config_json: String,
        ) -> Result<WasmWhisperPipeline, JsError> {
            let config = parse_whisper_config_json(&config_json).map_err(|e| JsError::new(&e))?;

            // Upcast the host backend's inner Arc to `dyn WeightBackend`.
            // `WasmHostBackend::as_weight_backend` is a `pub(crate)` shim
            // added in `src/wasm_bindings.rs` for exactly this purpose
            // (it sidesteps the existing private `clone_inner` field-shape
            // accessor). The returned `Arc` is independent of the JS
            // handle's lifetime — the host can keep calling `set_tensor`
            // and `evict` on `backend` between encode and decode.
            let backend_dyn: Arc<dyn WeightBackend> = backend.as_weight_backend();

            let inner = WhisperPipelineInner::new(backend_dyn, config);
            Ok(Self { inner })
        }

        /// Run the encoder. `mel` is a `Float32Array` of length
        /// `n_mels * n_frames` (typically `80 * 3000 = 240_000`).
        /// Returns a `Float32Array` of length
        /// `n_audio_ctx * encoder_hidden_dim` (typically
        /// `1500 * 384 = 576_000` for whisper-tiny).
        #[wasm_bindgen]
        pub fn encode(&mut self, mel: &[f32]) -> Vec<f32> {
            self.inner.encode(mel)
        }

        /// Greedy autoregressive decode. Returns the generated token
        /// ids (BOS excluded). Stops at `eos_token` or after
        /// `max_tokens` steps, whichever fires first.
        #[wasm_bindgen]
        pub fn generate(
            &mut self,
            encoder_output: &[f32],
            max_tokens: u32,
            eos_token: u32,
        ) -> Vec<u32> {
            self.inner.generate(encoder_output, max_tokens, eos_token)
        }

        /// Prime cross-attention K/V from an encoder output and reset the
        /// autoregressive self-attention cache for a new utterance.
        #[wasm_bindgen]
        pub fn load_audio_context(&mut self, encoder_output: &[f32]) {
            self.inner.load_audio_context(encoder_output)
        }

        /// Reset only the autoregressive decoder self-attention cache.
        #[wasm_bindgen]
        pub fn reset_decoder(&mut self) {
            self.inner.reset_decoder()
        }

        /// Run one decoder step and return the real next-token logits.
        #[wasm_bindgen]
        pub fn decode_step_logits(&mut self, token: u32, pos: u32) -> Vec<f32> {
            self.inner.decode_step_logits(token, pos)
        }

        /// Override the BOS token used by the next `generate` call.
        /// Defaults to `50258` (multilingual). Set to `50257` for
        /// `whisper-*.en` checkpoints, or any other special-token id
        /// for forced-prompt experiments.
        #[wasm_bindgen]
        pub fn set_bos_token(&mut self, bos: u32) {
            self.inner.bos_token = bos;
        }

        /// Override the forced decoder prefix used by the next `generate`
        /// call. Defaults to `[50258, 50259, 50359, 50363]`
        /// (`<|sot|><|en|><|transcribe|><|notimestamps|>`). Pass an empty
        /// array to restore legacy BOS-only seeding, or a custom prefix
        /// for other languages / translation / timestamped decoding.
        #[wasm_bindgen]
        pub fn set_forced_prefix(&mut self, prefix: Vec<u32>) {
            self.inner.set_forced_prefix(prefix);
        }

        #[wasm_bindgen]
        pub fn memo_enable(&mut self, on: bool) {
            self.inner.memo_enable(on);
        }

        #[wasm_bindgen]
        pub fn memo_stats(&self) -> Vec<u32> {
            self.inner.memo_stats()
        }

        #[wasm_bindgen]
        pub fn memo_clear(&mut self) {
            self.inner.memo_clear();
        }
    }
}

#[cfg(target_arch = "wasm32")]
pub use wasm_surface::WasmWhisperPipeline;

// ─────────────────────────────────────────────────────────────────────────
// NAPI wrapper (native + `napi` feature)
// ─────────────────────────────────────────────────────────────────────────

#[cfg(all(not(target_arch = "wasm32"), feature = "napi"))]
mod napi_surface {
    use super::*;
    use crate::loader::KnotWeights;
    use napi::bindgen_prelude::*;
    use napi_derive::napi;

    /// Node.js-callable Whisper STT pipeline. Mirrors the WASM API so
    /// host code can be written once and target either runtime.
    ///
    /// Unlike the WASM wrapper, this constructor takes a `path` to a
    /// `.knot` file — Node has direct filesystem access, so the
    /// host-driven `WasmHostBackend` indirection isn't needed. The
    /// path is opened via `KnotWeights::load`, and the resulting
    /// `Arc<dyn WeightBackend>` is handed to the encoder + decoder.
    #[napi]
    pub struct WhisperPipeline {
        inner: WhisperPipelineInner,
    }

    #[napi]
    impl WhisperPipeline {
        /// Open a whisper `.knot` file and build a pipeline.
        ///
        /// `config_json` is the stringified `WhisperConfig`. Pass the
        /// `config` block from the knot's metadata; the helper accepts
        /// either the bare config or a `{ "config": {...} }` envelope.
        #[napi(constructor)]
        pub fn napi_new(path: String, config_json: String) -> napi::Result<Self> {
            let knot = KnotWeights::load(&path)
                .map_err(|e| napi::Error::from_reason(format!("knot load: {}", e)))?;
            let config = parse_whisper_config_json(&config_json)
                .map_err(|e| napi::Error::from_reason(format!("config parse: {}", e)))?;
            let inner = WhisperPipelineInner::new(knot.backend, config);
            Ok(Self { inner })
        }

        /// Run the encoder. Mirrors `WasmWhisperPipeline::encode`.
        #[napi(js_name = "encode")]
        pub fn napi_encode(&mut self, mel: Float32Array) -> Float32Array {
            let out = self.inner.encode(mel.as_ref());
            Float32Array::new(out)
        }

        /// Greedy autoregressive decode. Mirrors
        /// `WasmWhisperPipeline::generate`.
        #[napi(js_name = "generate")]
        pub fn napi_generate(
            &mut self,
            encoder_output: Float32Array,
            max_tokens: u32,
            eos_token: u32,
        ) -> Uint32Array {
            let out = self
                .inner
                .generate(encoder_output.as_ref(), max_tokens, eos_token);
            Uint32Array::new(out)
        }

        #[napi(js_name = "loadAudioContext")]
        pub fn napi_load_audio_context(&mut self, encoder_output: Float32Array) {
            self.inner.load_audio_context(encoder_output.as_ref());
        }

        #[napi(js_name = "resetDecoder")]
        pub fn napi_reset_decoder(&mut self) {
            self.inner.reset_decoder();
        }

        #[napi(js_name = "decodeStepLogits")]
        pub fn napi_decode_step_logits(&mut self, token: u32, pos: u32) -> Float32Array {
            let out = self.inner.decode_step_logits(token, pos);
            Float32Array::new(out)
        }

        /// Override the BOS token used by the next `generate` call.
        #[napi(js_name = "setBosToken")]
        pub fn napi_set_bos_token(&mut self, bos: u32) {
            self.inner.bos_token = bos;
        }

        /// Override the forced decoder prefix used by the next `generate`
        /// call. Defaults to `[50258, 50259, 50359, 50363]`
        /// (`<|sot|><|en|><|transcribe|><|notimestamps|>`). Pass an empty
        /// array to restore legacy BOS-only seeding.
        #[napi(js_name = "setForcedPrefix")]
        pub fn napi_set_forced_prefix(&mut self, prefix: Vec<u32>) {
            self.inner.set_forced_prefix(prefix);
        }

        #[napi(js_name = "memoEnable")]
        pub fn napi_memo_enable(&mut self, on: bool) {
            self.inner.memo_enable(on);
        }

        #[napi(js_name = "memoStats")]
        pub fn napi_memo_stats(&self) -> Vec<u32> {
            self.inner.memo_stats()
        }

        #[napi(js_name = "memoClear")]
        pub fn napi_memo_clear(&mut self) {
            self.inner.memo_clear();
        }
    }
}

#[cfg(all(not(target_arch = "wasm32"), feature = "napi"))]
pub use napi_surface::WhisperPipeline;

// ─────────────────────────────────────────────────────────────────────────
// Native (no-wasm, no-napi) — expose the shared inner pipeline so native
// tests / probes / bins can exercise the exact fixed `generate()` path
// without going through the wasm-bindgen or NAPI ABI. This is the engine
// the mesh runs; the wasm/napi wrappers are thin newtypes over it.
// ─────────────────────────────────────────────────────────────────────────

#[cfg(not(target_arch = "wasm32"))]
pub use self::WhisperPipelineInner as NativeWhisperPipeline;
